import type {
  BaseProbeResult,
  BlockStreamingCoalesceConfig,
  DmConfig,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
  MarkdownConfig,
  OpenClawConfig,
} from "./runtime-api.js";

export type PulseBoardGroupConfig = {
  /** Whether the bot must be @-mentioned to respond in a board. Defaults to true. */
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** Base URL of the PulseBoard server (e.g. https://pulseboard.example.com). */
  url?: string;
  /** API token for authenticating with the PulseBoard server. */
  apiToken?: string;
  /** Optional file path containing the API token. */
  apiTokenFile?: string;
  /** Bot username on the PulseBoard server. */
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration, keyed by board name (including the "#" prefix). */
  boards?: Record<string, PulseBoardGroupConfig>;
  defaultTo?: string;
  markdown?: MarkdownConfig;
  historyLimit?: number;
  dmHistoryLimit?: number;
  dms?: Record<string, DmConfig>;
  /** Override the 4000-character default chunk limit. */
  textChunkLimit?: number;
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** A normalized inbound message from PulseBoard. */
export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: board name (e.g. "#general") for groups, sender username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  url: string;
  username: string;
  latencyMs?: number;
};

