// PulseBoard target normalization.
// Boards use a "#name" prefix (e.g. "#general", "#announcements").
// Direct-message targets are plain lowercase usernames.

const BOARD_TARGET_PATTERN = /^#[a-z0-9_-]{1,100}$/iu;
const USER_TARGET_PATTERN = /^[a-z0-9_.-]{1,100}$/iu;

/** Returns true if the normalized target refers to a board (group chat). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw user input into a canonical PulseBoard target.
 * Returns undefined for inputs that cannot be resolved to a valid target.
 *
 * Accepted forms:
 *   "#general"              → "#general"   (board)
 *   "board:general"         → "#general"   (board with explicit prefix)
 *   "pulseboard:#general"   → "#general"   (scheme-prefixed board)
 *   "alice"                 → "alice"       (DM user)
 *   "user:alice"            → "alice"       (DM with explicit prefix)
 *   "pulseboard:alice"      → "alice"       (scheme-prefixed DM)
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;

  // Strip "pulseboard:" scheme prefix.
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // "board:" prefix → ensure "#" prefix for the board name.
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }

  // "user:" prefix → strip it.
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }
  return target;
}

/** Heuristic check for whether a string looks like a valid PulseBoard target. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return BOARD_TARGET_PATTERN.test(trimmed) || USER_TARGET_PATTERN.test(trimmed);
}

/** Normalize a raw allowFrom entry to a canonical lowercase username or "*". */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value === "*") {
    return "*";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

/** Normalize an allowFrom list, filtering out empty entries. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
    .filter(Boolean);
}

/** Check whether a sender username matches an allowFrom list. */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  senderUsername: string;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidate = params.senderUsername.trim().toLowerCase();
  if (candidate && allowFrom.has(candidate)) {
    return { allowed: true, source: candidate };
  }
  return { allowed: false };
}

