import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probe the PulseBoard server by calling its health endpoint.
 * Returns the latency in milliseconds on success.
 */
export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = {
    ok: false,
    url: account.url,
    username: account.username,
  };

  if (!account.configured) {
    return { ...base, error: "missing url, username, or apiToken" };
  }

  const started = Date.now();
  const controller = new AbortController();
  const timeoutMs = opts?.timeoutMs ?? 8000;
  const timerId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(`${account.url}/api/health`, {
      headers: { Authorization: `Bearer ${account.apiToken}` },
      signal: controller.signal,
    });
    if (!response.ok) {
      return { ...base, error: `HTTP ${response.status}` };
    }
    return { ...base, ok: true, latencyMs: Date.now() - started };
  } catch (err) {
    return { ...base, error: formatError(err) };
  } finally {
    clearTimeout(timerId);
  }
}

