import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardMessagingTarget, isBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    // Ignore if runtime is not initialized (e.g. during transient sends before gateway starts).
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

/** Build the PulseBoard REST endpoint URL for a given target. */
function resolvePostEndpoint(baseUrl: string, target: string): string {
  if (isBoardTarget(target)) {
    // Strip the leading "#" to get the bare board name.
    return `${baseUrl}/api/boards/${encodeURIComponent(target.slice(1))}/messages`;
  }
  return `${baseUrl}/api/dm/${encodeURIComponent(target)}/messages`;
}

/**
 * Send a message to a PulseBoard board or direct-message target.
 *
 * Uses the PulseBoard REST API (POST /api/boards/:name/messages or
 * POST /api/dm/:username/messages).
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need url, username, and apiToken in channels.pulseboard).`,
    );
  }

  const target = normalizePulseBoardMessagingTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const endpoint = resolvePostEndpoint(account.url, target);
  const response = await fetch(endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${account.apiToken}`,
