import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { isBoardTarget } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

/** Raw event shape delivered by the PulseBoard WebSocket stream. */
type PulseBoardWsEvent = {
  type: string;
  id: string;
  /** Board name (e.g. "#general") for board posts, or recipient username for DMs. */
  target: string;
  senderUsername: string;
  text: string;
  /** Unix millisecond timestamp. */
  timestamp: number;
  /** true when the message was posted to a board rather than sent as a DM. */
  isBoard: boolean;
};

/**
 * Connect to the PulseBoard WebSocket event stream and dispatch inbound messages.
 * Reconnects automatically on unexpected disconnection.
 *
 * Returns a handle with a `stop()` method that tears down the connection.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need url, username, and apiToken in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let stopped = false;
  let ws: WebSocket | null = null;
  let reconnectTimer: ReturnType<typeof setTimeout> | null = null;

  /** Build the WebSocket endpoint URL from the HTTP base URL. */
  function buildWsUrl(): string {
    const httpUrl = account.url.replace(/\/+$/, "");
    const wsBase = httpUrl.replace(/^https?/, (m) => (m === "https" ? "wss" : "ws"));
    return `${wsBase}/ws/events?token=${encodeURIComponent(account.apiToken)}`;
  }

  /** Build the REST POST URL for a reply target. */
  function buildReplyEndpoint(target: string): string {
    if (isBoardTarget(target)) {
      return `${account.url}/api/boards/${encodeURIComponent(target.slice(1))}/messages`;
    }
    return `${account.url}/api/dm/${encodeURIComponent(target)}/messages`;
  }

  function scheduleReconnect(): void {
    if (stopped) {
      return;
    }
    reconnectTimer = setTimeout(() => {
      reconnectTimer = null;
      connect();
    }, 5000);
  }

  function connect(): void {
    if (stopped) {
      return;
    }

    ws = new WebSocket(buildWsUrl());

    ws.addEventListener("open", () => {
      logger.info(
        `[${account.accountId}] connected to PulseBoard at ${account.url} as ${account.username}`,
      );
    });

    ws.addEventListener("message", async (event: MessageEvent) => {
      let parsed: PulseBoardWsEvent;
      try {
        parsed = JSON.parse(String(event.data)) as PulseBoardWsEvent;
      } catch {
        return;
      }

      if (parsed.type !== "message") {
        return;
      }

      // Skip messages sent by the bot itself.
      if (parsed.senderUsername === account.username) {
        return;
      }

      const message: PulseBoardInboundMessage = {
        messageId: parsed.id,
        target: parsed.target,
        senderUsername: parsed.senderUsername,
        text: parsed.text ?? "",
        timestamp: parsed.timestamp ?? Date.now(),
        isGroup: parsed.isBoard,
      };

      core.channel.activity.record({
        channel: "pulseboard",
        accountId: account.accountId,
        direction: "inbound",
        at: message.timestamp,
      });

      if (opts.onMessage) {
        await opts.onMessage(message);
        return;
      }

      await handlePulseBoardInbound({
        message,
        account,
        config: cfg,
        runtime,
        sendReply: async (target, text) => {
          await fetch(buildReplyEndpoint(target), {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              Authorization: `Bearer ${account.apiToken}`,
            },
            body: JSON.stringify({ text }),
          });
          opts.statusSink?.({ lastOutboundAt: Date.now() });
          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "outbound",
          });
        },
        statusSink: opts.statusSink,
      });
    });

    ws.addEventListener("error", (event: Event) => {
      logger.error(`[${account.accountId}] PulseBoard WebSocket error: ${String(event)}`);
    });

    ws.addEventListener("close", () => {
      ws = null;
      if (!stopped) {
        logger.info(`[${account.accountId}] PulseBoard disconnected — reconnecting in 5 s`);
        scheduleReconnect();
      }
    });
  }

  // Honor the abort signal for clean gateway shutdown.
  opts.abortSignal?.addEventListener("abort", () => {
    stopped = true;
    if (reconnectTimer !== null) {
      clearTimeout(reconnectTimer);
      reconnectTimer = null;
    }
    ws?.close();
    ws = null;
  });

  connect();

  return {
    stop: () => {
      stopped = true;
      if (reconnectTimer !== null) {
        clearTimeout(reconnectTimer);
        reconnectTimer = null;
      }
      ws?.close();
      ws = null;
    },
  };
}

