import type { DmPolicy } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createAllowFromSection,
  createPromptParsedAllowFromForAccount,
  createStandardChannelSetupStatus,
  formatDocsLink,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard, WizardPrompter } from "openclaw/plugin-sdk/setup";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  resolveDefaultPulseBoardAccountId,
} from "./accounts.js";
import { normalizePulseBoardAllowEntry, normalizePulseBoardMessagingTarget } from "./normalize.js";
import {
  pulseBoardSetupAdapter,
  setPulseBoardAllowFrom,
  setPulseBoardDmPolicy,
  updatePulseBoardAccountConfig,
} from "./setup-core.js";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

const channel = "pulseboard" as const;

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

async function promptPulseBoardCredentials(
  prompter: WizardPrompter,
  existing?: PulseBoardAccountConfig,
): Promise<{ url: string; username: string; apiToken: string }> {
  const url = await prompter.text({
    message: "PulseBoard server URL",
    placeholder: "https://pulseboard.example.com",
    initialValue: existing?.url ?? "",
    validate: (v) => (v.trim() ? undefined : "Server URL is required."),
  });

  const username = await prompter.text({
    message: "Bot username on PulseBoard",
    placeholder: "mybot",
    initialValue: existing?.username ?? "",
    validate: (v) => (v.trim() ? undefined : "Username is required."),
  });

  const apiToken = await prompter.password({
    message: "PulseBoard API token",
    validate: (v) => (v.trim() ? undefined : "API token is required."),
  });

  return { url: url.trim(), username: username.trim(), apiToken: apiToken.trim() };
}

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  label: "PulseBoard",
  docsUrl: formatDocsLink("/channels/pulseboard"),

  async status({ cfg }) {
    return createStandardChannelSetupStatus({
      cfg: cfg as CoreConfig,
      channel,
      listAccountIds: listPulseBoardAccountIds,
      resolveAccount: (c, accountId) => resolvePulseBoardAccount({ cfg: c as CoreConfig, accountId }),
      resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
    });
  },

  async enable({ cfg, prompter }) {
    const coreCfg = cfg as CoreConfig;
    const accountId = resolveDefaultPulseBoardAccountId(coreCfg) ?? DEFAULT_ACCOUNT_ID;
    const existing = resolvePulseBoardAccount({ cfg: coreCfg, accountId });

    prompter.intro("Set up PulseBoard");

    // Collect connection credentials.
    const { url, username, apiToken } = await promptPulseBoardCredentials(
      prompter,
      existing.config,
    );

    let updated = updatePulseBoardAccountConfig(coreCfg, accountId, {
      enabled: true,
      url,
      username,
      apiToken,
    });

    // DM policy.
    const dmPolicyChoice = (await prompter.select({
      message: "Who can send you direct messages?",
      options: [
        { value: "pairing", label: "Pairing required (recommended)" },
        { value: "allowlist", label: "Allowlist only" },
        { value: "open", label: "Anyone (open)" },
        { value: "disabled", label: "Disabled" },
      ],
      initialValue: existing.config.dmPolicy ?? "pairing",
    })) as DmPolicy;

    updated = setPulseBoardDmPolicy(updated, dmPolicyChoice);

    // Allow-from list for pairing/allowlist policies.
    if (dmPolicyChoice === "allowlist") {
      const allowFrom = await prompter.text({
        message: "Allowed usernames (comma-separated)",
        placeholder: "alice, bob",
        initialValue: (existing.config.allowFrom ?? []).join(", "),
      });
      const entries = parseListInput(allowFrom)
        .map(normalizePulseBoardAllowEntry)
        .filter(Boolean);
      updated = setPulseBoardAllowFrom(updated, entries);
    }

    prompter.outro(`PulseBoard configured for ${username} at ${url}`);
    return updated;
  },

  async disable({ cfg }) {
    return setSetupChannelEnabled(cfg as CoreConfig, channel, false) as CoreConfig;
  },

  async configure({ cfg, prompter }) {
    const coreCfg = cfg as CoreConfig;
    const accountId = resolveDefaultPulseBoardAccountId(coreCfg) ?? DEFAULT_ACCOUNT_ID;
    const existing = resolvePulseBoardAccount({ cfg: coreCfg, accountId });

    prompter.intro("Configure PulseBoard");

    const { url, username, apiToken } = await promptPulseBoardCredentials(
      prompter,
      existing.config,
    );

    const updated = updatePulseBoardAccountConfig(coreCfg, accountId, {
      enabled: true,
      url,
      username,
      apiToken,
    });

    prompter.outro("PulseBoard configuration updated.");
    return updated;
  },

  allowFrom: createAllowFromSection({
    channel,
    parseEntries: (raw) =>
      parseListInput(raw).map(normalizePulseBoardAllowEntry).filter(Boolean),
    promptForAccount: createPromptParsedAllowFromForAccount({
      channel,
      listAccountIds: listPulseBoardAccountIds,
      resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
      normalizeEntry: normalizePulseBoardAllowEntry,
    }),
  }),

  setupAdapter: pulseBoardSetupAdapter,
};

